
import { cloneDeep } from "lodash-es";
import { DownOutlined } from "@ant-design/icons-vue";
import {
  defineComponent,
  onMounted,
  reactive,
  ref,
  toRefs,
  UnwrapRef,
  watch,
} from "vue";
import {
  reportEdit,
  preserveCkeck,
  download_init,
  getQuota,
} from "@/server/http/api/Amultitasking";
import { useRoute } from "vue-router";
import ReturnTitle from "@/components/OS_component/ReturnTitle.vue";
import DownloadCheck from "../../model/Reportgeneration/DownloadCheck.vue";
import { message } from "ant-design-vue";
const columns = [
  {
    title: "样品名称",
    dataIndex: "sampleName",
    key: "sampleName",
  },
  {
    title: "样品编号",
    dataIndex: "sampleCode",
    key: "sampleCode",
  },
];
const columns1 = [
  {
    title: "序号",
    dataIndex: "index",
    key: "index",
  },
  {
    title: "检测项",
    dataIndex: "checkItemName",
    key: "checkItemName",
  },
  {
    title: "技术指标",
    dataIndex: "specsContent",
    slots: { customRender: "specsContent" },
    width: "20%",
  },
  {
    title: "检测结果",
    key: "checkResult",

    slots: { customRender: "checkResult" },
    width: "20%",
  },
  {
    title: "结果判定",
    key: "judgeResult",
    width: "20%",
    slots: { customRender: "judgeResult" },
  },
  {
    title: "编辑",
    dataIndex: "operation",
    width: "20%",
    slots: { customRender: "operation" },
  },
];

export default defineComponent({
  components: { ReturnTitle, DownOutlined, DownloadCheck },
  setup() {
    const Quota = ref("");

    const QuotaList = ref([]);

    let options: any = reactive({
      details: {},
    });
    const loading = ref(false);
    const dataSource: any = ref({});
    const route: any = useRoute();
    onMounted(() => {
      getQuota(route.query.taskId).then((res: any) => {
        if (res.data.code === 200) {
          QuotaList.value = res.data.data;
        }
      });
    });
    watch(Quota, (newval) => {
      //   console.log(newval);
      let QuotaSpecsList: any = QuotaList.value.filter((item: any) => {
        return item.key === newval;
      });
      //   console.log(QuotaSpecsList[0].value);
      options.details.samples.map((val: any) => {
        let arr: any = [];
        val.checkItems.map((item: any, i: number) => {
          let obj: any = {};
          obj = item;
          obj.index = i + 1;
          obj.sampleId = val.sampleId;
          obj.key = item.checkItemId;
          obj.checkItemName = item.checkItemName;
          QuotaSpecsList[0].value.map((o: any) => {
            if (o.checkItemId === item.checkItemId) {
              obj.specsContent = o.specsContent;
            }
          });
          arr.push(obj);
        });
        dataSource.value[val.sampleId] = arr;
      });
    });
    reportEdit(route.query.taskId).then((res: any) => {
      //console.log("编辑数据", res);
      if (res.data.code === 200) {
        options.details = res.data.data;
        res.data.data.samples.map((val: any) => {
          let arr: any = [];
          val.checkItems.map((item: any, i: number) => {
            let obj: any = {};
            obj = item;
            obj.index = i + 1;
            obj.sampleId = val.sampleId;
            obj.key = item.checkItemId;
            obj.checkItemName = item.checkItemName;

            arr.push(obj);
          });
          dataSource.value[val.sampleId] = arr;
        });
      }
    });

    const editableData: UnwrapRef<Record<string, any>> = reactive({});

    const edit = (key: string, id: number) => {
      editableData[key] = cloneDeep(
        dataSource.value[id].filter((item: any) => key === item.key)[0]
      );
    };
    const save = (key: string, id: number) => {
      Object.assign(
        dataSource.value[id].filter((item: any) => key === item.key)[0],
        editableData[key]
      );
      delete editableData[key];
    };
    const cancel = (key: string) => {
      delete editableData[key];
    };

    const handleMenuClick = (e: Event) => {
      //console.log("click", e);
    };
    // 保存
    function preserve() {
      loading.value = true;
      let willdata: any = {};
      //   保存基本数据
      willdata.taskId = route.query.taskId;
      willdata.entrustmentId = options.details.id;
      willdata.sampleName = options.details.sampleName;
      willdata.price = options.details.countPrice;
      willdata.requiredCompletionTime = options.details.requestDate;
      willdata.taskCode = options.details.taskCode;
      willdata.number = options.details.reportCount;
      willdata.reportType = options.details.reportType;
      willdata.checkInfos = [];
      // 保存检测项编辑数据
      for (let key in dataSource.value) {
        dataSource.value[key].map((item: any) => {
          willdata.checkInfos.push({
            checkItemId: item.checkItemId,
            checkItemName: item.checkItemName,
            specsContent: item.specsContent,
            checkResult: item.checkResult,
            judgeResult: item.judgeResult,
            coordinate: item.coordinate,
          });
        });
      }
      //console.log(willdata);
      preserveCkeck(willdata)
        .then(
          (res: any) => {
            //console.log(res);
            if (res.data.code === 200) {
              loading.value = false;
              message.success("保存成功！");
            }
          },
          () => {
            loading.value = false;
          }
        )
        .catch(() => {
          loading.value = false;
        });
    }
    // 下载原始记录
    function downloadinit(checkItemId: number) {
      download_init(checkItemId).then((res: any) => {
        const link = document.createElement("a");
        link.style.display = "none";
        link.setAttribute("href", res.data);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
      });
    }
    return {
      dataSource,
      columns,
      editingKey: "",
      editableData,
      edit,
      save,
      cancel,
      ...toRefs(options),
      columns1,
      handleMenuClick,
      preserve,
      downloadinit,
      loading,
      Quota,
      QuotaList,
    };
  },
});
