
const columns = [
  {
    title: "报告名称",
    dataIndex: "reportName",
    key: "reportName",
  },
  {
    title: "编号",
    dataIndex: "reportCode",
    key: "reportCode",
  },

  {
    title: "操作",

    key: "action",
    slots: { customRender: "action" },
  },
];

import { defineComponent, ref } from "vue";
import {
  getTemplateList,
  approval_download,
} from "@/server/http/api/Amultitasking";
import PreviewCheck from "./PreviewCheck.vue";
export default defineComponent({
  props: ["productId", "id"],
  components: { PreviewCheck },
  setup(props) {
    const visible = ref<boolean>(false);
    const dataSource = ref([]);
    const showModal = () => {
      getTemplateList(props.productId).then((res: any) => {
        if (res.data.code === 200) {
          dataSource.value = res.data.data;
        }
      });
      visible.value = true;
    };

    const handleOk = (e: MouseEvent) => {
      //console.log(e);
      visible.value = false;
    };
    function downLoad(record: any) {
      approval_download(props.id, record.reportFileUri).then((res: any) => {
        //console.log(res);
        const link = document.createElement("a");
        link.style.display = "none";
        link.setAttribute("href", res.data);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
      });
    }
    function preview() {}
    return {
      visible,
      showModal,
      handleOk,
      columns,
      dataSource,
      downLoad,
      preview,
    };
  },
});
